var webhookData = $input.first().json.body;
var base64Data = webhookData.csvData;
if (!base64Data) {
  throw new Error("No csvData found in request");
}

var datasetName = webhookData.datasetName || "Unnamed Dataset";
var description = webhookData.description || "";
var email = webhookData.email || "";

var csvText = Buffer.from(base64Data, "base64").toString("utf-8");

// Strip BOM if present
if (csvText.charCodeAt(0) === 0xFEFF) {
  csvText = csvText.slice(1);
}

// --- MULTILINE-AWARE CSV PARSER ---
function parseCSV(text) {
  const rows = [];
  let row = [];
  let cell = '';
  let inQuotes = false;

  for (let i = 0; i < text.length; i++) {
    const char = text[i];
    const next = text[i + 1];

    if (char === '"') {
      if (inQuotes && next === '"') {
        cell += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (char === ',' && !inQuotes) {
      row.push(cell.trim());
      cell = '';
    } else if (!inQuotes && (char === '\n' || char === '\r')) {
      if (char === '\r' && next === '\n') i++;
      row.push(cell.trim());
      if (row.some(v => v !== '')) {
        rows.push(row);
      }
      row = [];
      cell = '';
    } else {
      cell += char;
    }
  }

  // Flush final row
  if (cell || row.length) {
    row.push(cell.trim());
    if (row.some(v => v !== '')) {
      rows.push(row);
    }
  }

  return rows;
}
// ----------------------------------

var allRows = parseCSV(csvText);

if (allRows.length < 2) {
  throw new Error("CSV must have header and data rows");
}

var headers = allRows[0];
var rows = [];

for (var i = 1; i < allRows.length; i++) {
  var values = allRows[i];
  var row = {};
  for (var j = 0; j < headers.length; j++) {
    row[headers[j]] = values[j] !== undefined ? values[j] : "";
  }
  rows.push({ json: row });
}

if (rows.length === 0) {
  throw new Error("No data rows found");
}

$execution.customData.set("datasetName", datasetName);
$execution.customData.set("description", description);
$execution.customData.set("email", email);

return rows;

var items = $input.all();
if (items.length === 0) return { error: "No data received." };

var datasetName = $execution.customData.get("datasetName") || "Test";
var datasetDesc = $execution.customData.get("description") || "";
var email = $execution.customData.get("email") || "";

function detectType(val) {
  if (val === null || val === undefined || String(val).trim() === "") return "null";
  var str = String(val).trim();

  // 1. Enhanced Date Detection (Strict ISO, US Slanted, and Dash formats)
  var strictDate = /^\d{4}-\d{2}-\d{2}$|^\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4}$/;
  // Also check if it's a valid date object string (like "2023-10-27T10:00:00Z")
  if (strictDate.test(str) || !isNaN(Date.parse(str)) && isNaN(str)) {
    return "date";
  }

  // 2. Boolean Detection
  if (str.toLowerCase() === "true" || str.toLowerCase() === "false") return "bool";

  // 3. Numeric Detection (Cleaned of currency/commas)
  var cleanNum = str.replace(/[$,]/g, "");
  if (cleanNum !== "" && !isNaN(cleanNum)) {
    if (str.indexOf(".") !== -1 || Math.abs(parseFloat(cleanNum)) > 999999) {
      return "real";
    }
    return "int";
  }

  return "string";
}

function getWinnerType(current, next) {
  if (!current || current === "null") return next;
  if (next === "null") return current;

  // Hierarchy: String kills everything. 
  // Dates should stay Dates unless mixed with text.
  if (current === "string" || next === "string") return "string";

  // If we have mixed Date and Numbers, we usually default to String
  if ((current === "date" && next !== "date") || (next === "date" && current !== "date")) {
    return "string";
  }

  if (current === "real" || next === "real") return "real";
  if (current === "int" && next === "int") return "int";

  return current;
}

var columnTypes = {};
items.forEach(function(item) {
  var entries = Object.entries(item.json);
  for (var i = 0; i < entries.length; i++) {
    var key = entries[i][0];
    var value = entries[i][1];
    var type = detectType(value);
    columnTypes[key] = getWinnerType(columnTypes[key], type);
  }
});

var counters = { string: 1, real: 1, int: 1, date: 1, bool: 1 };
var mapping = {};
var dictionary = {};
// Trim and deduplicate headers (trim before sort to group identical trimmed names)
var headers = [...new Set(Object.keys(columnTypes).map(k => k.trim()))].sort();
// Rebuild columnTypes with trimmed keys
var trimmedColumnTypes = {};
Object.keys(columnTypes).forEach(k => {
  var tk = k.trim();
  trimmedColumnTypes[tk] = getWinnerType(trimmedColumnTypes[tk], columnTypes[k]);
});
columnTypes = trimmedColumnTypes;

for (var i = 0; i < headers.length; i++) {
  var header = headers[i].trim();
  var type = columnTypes[header];
  if (type === "null") type = "string";

  // This creates column names like date1, date2, etc.
  var dbColumn = type + counters[type];
  mapping[header] = dbColumn;
  dictionary[dbColumn] = { 
    original_name: header, 
    data_type: type 
  };
  counters[type]++;
}

return {
  dataset_name: datasetName,
  dataset_summary: datasetDesc,
  owner_email: email,
  column_mapping: mapping,
  column_dictionary: dictionary,
  total_row_count: items.length
};

var items = $("Parse CSV").all();
if (items.length === 0) return [];

var shuffled = items.slice();
for (var i = shuffled.length - 1; i > 0; i--) {
  var j = Math.floor(Math.random() * (i + 1));
  var temp = shuffled[i];
  shuffled[i] = shuffled[j];
  shuffled[j] = temp;
}

return shuffled.slice(0, 300);

// 1. Get mapping and ID
const mappingNode = $("Mapping Logic").first();
const managerNode = $("Insert Record Manager").first();

if (!mappingNode || !managerNode) {
    throw new Error("Missing input from Mapping Logic or Insert Record Manager");
} 

const mapping = mappingNode.json.column_mapping;
const datasetId = managerNode.json.dataset_id;

// --- FIX IS HERE: Reference "Parse CSV" directly to get the data rows ---
const allRows = $("Parse CSV").all(); 

const results = [];
const batchSize = 100; // Smaller batches are safer for large SQL strings
const mapEntries = Object.entries(mapping);
const dbColumnNames = mapEntries.map(entry => entry[1]);

function isDateColumn(colName) {
    const lower = colName.toLowerCase();
    return lower.includes("date") || lower.includes("_at") || lower.includes("time");
}

function standardizeDate(val) {
    const d = new Date(val);
    return isNaN(d.getTime()) ? null : d.toISOString().split("T")[0];
}

function prepareValue(val, targetColumn) {
    if (val === null || val === undefined || String(val).trim() === "") return "NULL";

    let stringVal = String(val).trim();
    const colLower = targetColumn.toLowerCase();

    // Numeric handling (strip currency symbols and commas)
    if (colLower.startsWith("int") || colLower.startsWith("real") || colLower.startsWith("numeric")) {
        const cleanNum = stringVal.replace(/[,\s$]/g, "");
        if (cleanNum === "" || isNaN(cleanNum)) return "NULL";
        return cleanNum;
    }

    // Date handling
    if (isDateColumn(targetColumn)) {
        if (/^\d+$/.test(stringVal) && parseInt(stringVal) > 9999) return "NULL";
        const correctedDate = standardizeDate(stringVal);
        return correctedDate ? `'${correctedDate}'` : "NULL";
    }

    // String handling: Escape single quotes AND dollar signs
    const escaped = stringVal
        .replace(/'/g, "''")
        .replace(/\$/g, "$$$$"); 

    return `'${escaped}'`;
}

const columns = ['"dataset_id"', '"row_index"'].concat(dbColumnNames.map(c => `"${c}"`));

for (let i = 0; i < allRows.length; i += batchSize) {
    const chunk = allRows.slice(i, i + batchSize);
    const valuesList = chunk.map((item, idx) => {
        const row = item.json;
        // Ensure datasetId is wrapped in single quotes as it is a UUID/String
        const rowValues = [`'${datasetId}'`, i + idx + 1]; 

        mapEntries.forEach(entry => {
            rowValues.push(prepareValue(row[entry[0]], entry[1]));
        });
        return `(${rowValues.join(",")})`;
    });

    results.push({ 
        json: { 
            sql: `INSERT INTO n8n_data.universal_datatable (${columns.join(",")}) VALUES ${valuesList.join(",")};` 
        } 
    });
}

return results;

