=CREATE OR REPLACE VIEW n8n_data.v_ds_{{ $('Insert Record Manager').first().json.dataset_id.replace(/-/g, '_') }} AS
SELECT
    {{
      Object.entries($('Mapping Logic').first().json.column_mapping)
      .map(([name, col]) => {
        const safeName = (name && name.trim() !== "") ? name.trim() : `unnamed_${col}`;
        return `${col} AS "${safeName}"`;
      })
      .join(',\n    ')
    }}
FROM n8n_data.universal_datatable
WHERE dataset_id = '{{ $('Insert Record Manager').first().json.dataset_id }}';

