var rawText = $json.output || "";

// 1. Strip any markdown formatting the AI might add (e.g., ```json ... ```)
var jsonString = rawText.replace(/```[a-z]*\n?/g, "").replace(/```/g, "").trim();

var parsedData;
try {
  // 2. Parse the pure JSON array
  parsedData = JSON.parse(jsonString);
} catch (e) {
  // Safe fallback if the AI hallucinates bad JSON
  return { cleaned_summary: "Error parsing AI output: " + e.message + "\n\nRaw Output:\n" + rawText };
}

var mdRows = [];

// 3. Loop through the JSON objects and build your clean Markdown string
parsedData.forEach(function(col) {
  var sectionMd = "### Column name:" + col.column_header + "\n";

  if (col.data_type) sectionMd += "* **Data Type:** " + col.data_type + "\n";
  if (col.business_logic) sectionMd += "* **Business Logic:** " + col.business_logic + "\n";

  // Join the array of exact values with commas
  if (col.exact_values && col.exact_values.length > 0) {
    sectionMd += "* **Exact Values:** " + col.exact_values.join(", ") + "\n";
  }

  if (col.format_notes) sectionMd += "* **Format Notes:** " + col.format_notes + "\n";
  if (col.null_handling) sectionMd += "* **Null Handling:** " + col.null_handling + "\n";
  if (col.aggregation_warning) sectionMd += "* **Aggregation Warning:** " + col.aggregation_warning + "\n";

  mdRows.push(sectionMd);
});

// 4. Return the formatted markdown string to be passed to Postgres
return { cleaned_summary: mdRows.join("\n\n") };

